import math

def count_trailing_zeros(n):
    if n == 0: return 0
    if n < 0: return 0
    return int(math.log2(n & -n))

if __name__ == "__main__":
    print(f"Trailing zeros of 36 (100100): {count_trailing_zeros(36)}")

